def divisor(n):
    import math
    if n <= 0:
        return 0
    count = 0
    sqrt_n = int(math.sqrt(n))
    for i in range(1, sqrt_n + 1):
        if n % i == 0:
            if i * i == n:
                count += 1
            else:
                count += 2
    return count

assert divisor(15) == 4
assert divisor(12) == 6
